duration: 0.583 ms  statement: CREATE OR REPLACE FUNCTION check_order_integrity(p_order_id INTEGER)
RETURNS BOOLEAN AS $$
DECLARE
    v_amount DECIMAL;
    v_user_id INTEGER;
    v_status VARCHAR;
BEGIN
    SELECT amount, user_id, status INTO v_amount, v_user_id, v_status
    FROM orders WHERE id = p_order_id;

    IF NOT FOUND THEN
        RAISE WARNING 'Commande #% introuvable lors de la vérification d''intégrité', p_order_id;
        RETURN FALSE;
    END IF;

    IF v_amount > 1000 THEN
        RAISE WARNING 'Montant élevé détecté sur commande #%: % EUR — vérification manuelle requise', p_order_id, v_amount;
    END IF;

    IF v_status = 'pending' AND v_amount > 500 THEN
        RAISE NOTICE 'Commande #% en attente avec montant % EUR', p_order_id, v_amount;
    END IF;

    RETURN TRUE;
END;
$$ LANGUAGE plpgsql;

